       eprintln!("⚠️  WARNING: {}", command);
       eprintln!("This command is potentially dangerous.");
       eprintln!("(First occurrence this session - command allowed)");
       Outcome::Allow
   }
   ```

3. Soft block handler (requires confirmation):
   ```rust
